    private static String escapeHtml(String input) {
        return input.replaceAll("<", "&lt;")
                     .replaceAll(">", "&gt;")
                     .replaceAll("&", "&amp;")
                     .replaceAll("\"", "&quot;")
                     .replaceAll("'", "&#39;");
